CREATE TABLE public.token_devices (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), token text NOT NULL, device_fingerprint text NOT NULL, ip_address text, user_agent text, device_label text DEFAULT '', last_seen_at timestamptz DEFAULT now(), created_at timestamptz DEFAULT now(), UNIQUE (token, device_fingerprint)); ALTER TABLE public.token_devices ENABLE ROW LEVEL SECURITY; CREATE POLICY "Anyone can view token_devices" ON public.token_devices FOR SELECT USING (true); CREATE POLICY "Anyone can insert token_devices" ON public.token_devices FOR INSERT WITH CHECK (true); CREATE POLICY "Anyone can update token_devices" ON public.token_devices FOR UPDATE USING (true); CREATE POLICY "Anyone can delete token_devices" ON public.token_devices FOR DELETE USING (true);